  1	import React, { FC, useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2	import cn from 'classnames';
  3	
  4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  5	import { kubevirtConsole } from '@kubevirt-utils/utils/utils';
  6	import KeyTable from '@novnc/novnc/lib/input/keysym';
  7	import RFBCreate from '@novnc/novnc/lib/rfb';
  8	import { initLogging } from '@novnc/novnc/lib/util/logging';
  9	import { Tab, Tabs, TabTitleText } from '@patternfly/react-core';
 10	
 11	import { INSECURE, SECURE } from '../../utils/constants';
 12	import { isConnectionEncrypted, sleep } from '../../utils/utils';
 13	import { ConsoleState, WS, WSS } from '../utils/ConsoleConsts';
 14	import useCopyPasteConsole from '../utils/hooks/useCopyPasteConsole';
 15	
 16	import {
 17	  HORIZONTAL_TAB,
 18	  isShiftKeyRequired,
 19	  LATIN_1_FIRST_CHAR,
 20	  LATIN_1_LAST_CHAR,
 21	  LINE_FEED,
 22	} from './utils/util';
 23	import { VncConsoleProps } from './utils/VncConsoleTypes';
 24	import VncConnect from './VncConnect';
 25	
 26	import '@patternfly/react-styles/css/components/Consoles/VncConsole.css';
 27	import './vnc-console.scss';
 28	
 29	const { connected, connecting, disconnected } = ConsoleState;
 30	
 31	export const VncConsole: FC<VncConsoleProps> = ({
 32	  CustomConnectComponent = VncConnect,
 33	  hasGPU,
 34	  onConnect,
 35	  scaleViewport = true,
 36	  viewOnly = false,
 37	  vmi,
 38	}) => {
 39	  const { t } = useKubevirtTranslation();
 40	  const [rfb, setRfb] = useState<RFBCreate>();
 41	  const [status, setStatus] = useState<ConsoleState>(disconnected);
 42	  const [activeTabKey, setActiveTabKey] = useState<number | string>(0);
 43	  const pasteText = useCopyPasteConsole();
 44	  const staticRenderLocationRef = useRef(null);
 45	  const StaticRenderLocation = useMemo(
 46	    () => (
 47	      <div
 48	        className={cn('vnc-container', { hide: status !== connected })}
 49	        ref={staticRenderLocationRef}
 50	      />
 51	    ),
 52	    [staticRenderLocationRef, status],
 53	  );
 54	
 55	  const connect = useCallback(() => {
 56	    setStatus(connecting);
 57	    setRfb(() => {
 58	      const isEncrypted = isConnectionEncrypted();
 59	      const path = `api/kubernetes/apis/subresources.kubevirt.io/v1/namespaces/${vmi?.metadata?.namespace}/virtualmachineinstances/${vmi?.metadata?.name}/vnc`;
 60	      const port = window.location.port || (isEncrypted ? SECURE : INSECURE);
 61	      const url = `${isEncrypted ? WSS : WS}://${window.location.hostname}:${port}/${path}`;
 62	      const rfbInstnce = new RFBCreate(staticRenderLocationRef.current, url);
 63	      rfbInstnce?.addEventListener('connect', () => setStatus(connected));
 64	      rfbInstnce?.addEventListener('disconnect', () => {
 65	        setStatus(disconnected);
 66	      });
 67	      rfbInstnce?.addEventListener('securityfailure', () => {
 68	        setStatus(disconnected);
 69	      });
 70	      rfbInstnce.sendCtrlAlt1 = function sendCtrlAlt1() {
 71	        if (this._rfbConnectionState !== connected || this._viewOnly) {
 72	          return;
 73	        }
 74	        this.sendKey(KeyTable.XK_Control_L, 'ControlLeft', true);
 75	        this.sendKey(KeyTable.XK_Alt_L, 'AltLeft', true);
 76	        this.sendKey(KeyTable.XK_1, 'One', true);
 77	        this.sendKey(KeyTable.XK_1, 'One', false);
 78	        this.sendKey(KeyTable.XK_Alt_L, 'AltLeft', false);
 79	        this.sendKey(KeyTable.XK_Control_L, 'ControlLeft', false);
 80	      };
 81	      rfbInstnce.sendCtrlAlt2 = function sendCtrlAlt2() {
 82	        if (this._rfbConnectionState !== connected || this._viewOnly) {
 83	          return;
 84	        }
 85	        this.sendKey(KeyTable.XK_Control_L, 'ControlLeft', true);
 86	        this.sendKey(KeyTable.XK_Alt_L, 'AltLeft', true);
 87	        this.sendKey(KeyTable.XK_2, 'Two', true);
 88	        this.sendKey(KeyTable.XK_2, 'Two', false);
 89	        this.sendKey(KeyTable.XK_Alt_L, 'AltLeft', false);
 90	        this.sendKey(KeyTable.XK_Control_L, 'ControlLeft', false);
 91	      };
 92	      rfbInstnce.sendPasteCMD = async function sendPasteCMD() {
 93	        if (this._rfbConnectionState !== connected || this._viewOnly) {
 94	          return;
 95	        }
 96	        const clipboardText = await navigator?.clipboard?.readText?.();
 97	        const text = clipboardText || pasteText.current;
 98	        for (const codePoint of text) {
 99	          const codePointIndex = codePoint.codePointAt(0);
100	          if (codePointIndex === LINE_FEED) {
101	            this.sendKey(KeyTable.XK_Return);
102	          } else if (codePointIndex === HORIZONTAL_TAB) {
103	            this.sendKey(KeyTable.XK_Tab);
104	          } else if (codePointIndex >= LATIN_1_FIRST_CHAR && codePointIndex <= LATIN_1_LAST_CHAR) {
105	            // qemu maintains virtual keyboard state (caps lock, shift, etc)
106	            // keysyms are checked against that state and lower case version will be picked
107	            // if there is no shift/caps lock turn on
108	            const shiftRequired = isShiftKeyRequired(codePoint);
109	            shiftRequired && this.sendKey(KeyTable.XK_Shift_L, 'ShiftLeft', true);
110	            // long text is getting truncated without a delay
111	            await sleep(50);
112	            // Latin-1 set that maps directly to keysym
113	            this.sendKey(codePointIndex);
114	            shiftRequired && this.sendKey(KeyTable.XK_Shift_L, 'ShiftLeft', false);
115	          }
116	        }
117	      };
118	      rfbInstnce.viewOnly = viewOnly;
119	      rfbInstnce.scaleViewport = scaleViewport;
120	      onConnect?.(rfbInstnce);
121	      return rfbInstnce;
122	    });
123	  }, [
124	    vmi?.metadata?.namespace,
125	    vmi?.metadata?.name,
126	    viewOnly,
127	    scaleViewport,
128	    onConnect,
129	    pasteText,
130	  ]);
131	
132	  useEffect(() => {
133	    if (!rfb && status === disconnected) {
134	      try {
135	        initLogging('debug');
136	        connect();
137	      } catch (e) {
138	        kubevirtConsole.error(e);
139	      }
140	    }
141	
142	    return () => {
143	      if (rfb && status === connected) {
144	        rfb?.disconnect();
145	        onConnect?.(null);
146	      }
147	    };
148	  }, [onConnect, connect, rfb, status]);
149	
150	  return (
151	    <>
152	      {(status === disconnected || status === connecting) && (
153	        <CustomConnectComponent connect={connect} isConnecting={status === connecting} />
154	      )}
155	
156	      {hasGPU && status === connected && (
157	        <div className="vnc-screen-tabs">
158	          <Tabs
159	            style={{
160	              width: staticRenderLocationRef?.current?.lastElementChild?.lastElementChild?.width,
161	            }}
162	            activeKey={activeTabKey}
163	          >
164	            <Tab
165	              onClick={() => {
166	                rfb?.sendCtrlAlt1();
167	                setActiveTabKey(0);
168	              }}
169	              eventKey={0}
170	              title={<TabTitleText>{t('Screen 1')}</TabTitleText>}
171	            />
172	            <Tab
173	              onClick={() => {
174	                rfb?.sendCtrlAlt2();
175	                setActiveTabKey(1);
176	              }}
177	              eventKey={1}
178	              title={<TabTitleText>{t('Screen 2')}</TabTitleText>}
179	            />
180	          </Tabs>
181	        </div>
182	      )}
183	      {StaticRenderLocation}
184	    </>
185	  );
186	};
187	
188	export default VncConsole;

